def translate_segment_text(text):
    # This function needs to be smarter to handle markdown formatting
    # and only translate the actual text, not the markdown syntax.

    # Placeholders for markdown elements
    placeholders = {}
    
    def replace_markdown_with_placeholder(match):
        full_match = match.group(0)
        placeholder_key = f"__MARKDOWN_PLACEHOLDER_{len(placeholders)}__"
        placeholders[placeholder_key] = full_match
        return placeholder_key

    # Temporarily replace bold, italic, and code blocks
    # Inline code (`)
    text = re.sub(r'`[^`]+`', replace_markdown_with_placeholder, text)
    # Bold (**)
    text = re.sub(r'\*\*[^*]+\*\*', replace_markdown_with_placeholder, text)
    # Italic (*)
    text = re.sub(r'\*[^*]+\*', replace_markdown_with_placeholder, text)
    # Links [text](url)
    text = re.sub(r'\[([^\]]+)\]\(([^)]+)\)', replace_markdown_with_placeholder, text)

    # Translate using glossary
    translated_text_parts = []
    
    # Split text by spaces and process words, but also handle punctuation carefully
    # This is a simplification. A more robust solution would use a proper tokenizer.
    words = re.findall(r'\b\w+\b|\s|\S', text) # Finds words, whitespace and non-whitespace characters
    
    for word in words:
        # Check for direct match in glossary (case-insensitive for check, but use original case for replacement)
        found_in_glossary = False
        for key, value in global_glossary.items():
            if re.fullmatch(r'\b' + re.escape(key) + r'\b', word, re.IGNORECASE):
                translated_text_parts.append(value)
                found_in_glossary = True
                break
        if not found_in_glossary:
            translated_text_parts.append(word)

    translated_text = "".join(translated_text_parts) # Join back to preserve spacing

    # Apply any specific phrase translations
    for original_phrase, translated_phrase in global_glossary.items():
        # Ensure we're only replacing full phrases, not parts of words
        translated_text = re.sub(r'\b' + re.escape(original_phrase) + r'\b', translated_phrase, translated_text)


    # Restore markdown elements
    for placeholder_key, original_markdown in placeholders.items():
        translated_text = translated_text.replace(placeholder_key, original_markdown)

    return translated_text

def translate_segments_file_content(segments_data_content):
    # Translate frontmatter segments
    for segment in segments_data_content["frontmatter_segments"]:
        if segment["key"] in ["title", "description", "measurable_at_this_level", "assessment_method", "extension_for_advanced", "remedial_for_struggling", "session_title", "source_lessons", "category", "bloom_level", "digcomp_area", "assessment"]:
            segment["translated"] = global_glossary.get(segment["original"], translate_segment_text(segment["original"]))
        else:
            segment["translated"] = segment["original"] # Keep other frontmatter keys as is

    # Translate body segments
    for segment in segments_data_content["body_segments"]:
        if segment["type"] == "inline":
            segment["translated"] = global_glossary.get(segment["original"], translate_segment_text(segment["original"]))
        elif segment["type"] == "table_row":
            for cell in segment["cells"]:
                cell["translated"] = global_glossary.get(cell["original"], translate_segment_text(cell["original"]))
        else:
            segment["translated"] = segment["original"]
    
    return segments_data_content

